targets.query:
import "date"

from(bucket: "cgmsharp")
  |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
  |> filter(fn: (r) => r._measurement == "glucose" and r._field == "value")
  |> map(fn: (r) => ({
    _value: r._value,
    _field: string(v: date.monthDay(t: r._time)) + "/" + string(v: int(v: date.month(t: r._time))),
    _time: time(v: int(v: r._time) - int(v: date.truncate(t: r._time, unit: 1d)))
  }))
  |> group(columns: ["_field"])
